class ASTNode:
    def __init__(self, type, **kwargs):
        self.type = type
        if type == 'number':
            self.value = kwargs.get('value')
        elif type == 'binop':
            self.op = kwargs.get('op')
            self.left = kwargs.get('left')
            self.right = kwargs.get('right')
        elif type == 'unary':
            self.op = kwargs.get('op')
            self.operand = kwargs.get('operand')

    def __repr__(self):
        if self.type == 'number':
            return f"Number({self.value})"
        elif self.type == 'binop':
            return f"BinOp({self.op}, {self.left}, {self.right})"
        elif self.type == 'unary':
            return f"Unary({self.op}, {self.operand})"


def parse(expression: str) -> ASTNode:
    if not expression.strip():
        raise ValueError("Empty expression")

    tokens = tokenize(expression)
    if not tokens:
        raise ValueError("No tokens found in expression")

    parser = Parser(tokens)
    return parser.parse()


def tokenize(expression: str) -> list:
    tokens = []
    i = 0
    n = len(expression)

    while i < n:
        c = expression[i]

        if c.isspace():
            i += 1
            continue

        if c.isdigit() or c == '.':
            num_str = ''
            while i < n and (expression[i].isdigit() or expression[i] == '.'):
                num_str += expression[i]
                i += 1
            try:
                tokens.append(('number', float(num_str)))
            except ValueError:
                raise ValueError(f"Invalid number format: {num_str}")
            continue

        if c in '+-*/()':
            tokens.append(('operator', c))
            i += 1
            continue

        raise ValueError(f"Invalid character: {c}")

    return tokens


class Parser:
    def __init__(self, tokens: list):
        self.tokens = tokens
        self.current = 0
        self.peek_token = None

    def parse(self) -> ASTNode:
        self.peek_token = self.tokens[0] if self.tokens else None
        return self.parse_expression()

    def peek(self):
        if self.current < len(self.tokens):
            return self.tokens[self.current]
        return None

    def consume(self):
        token = self.peek()
        self.current += 1
        self.peek_token = self.peek()
        return token

    def expect(self, expected_type):
        token = self.consume()
        if token is None or token[0] != expected_type:
            raise ValueError(f"Expected {expected_type}, got {token}")
        return token

    def parse_expression(self):
        return self.parse_addition()

    def parse_addition(self):
        node = self.parse_multiplication()

        while self.peek() and self.peek()[1] in ('+', '-'):
            op = self.consume()[1]
            right = self.parse_multiplication()
            node = ASTNode('binop', op=op, left=node, right=right)

        return node

    def parse_multiplication(self):
        node = self.parse_unary()

        while self.peek() and self.peek()[1] in ('*', '/'):
            op = self.consume()[1]
            right = self.parse_unary()
            node = ASTNode('binop', op=op, left=node, right=right)

        return node

    def parse_unary(self):
        if self.peek() and self.peek()[1] == '-':
            self.consume()
            operand = self.parse_primary()
            return ASTNode('unary', op='-', operand=operand)

        return self.parse_primary()

    def parse_primary(self):
        if not self.peek():
            raise ValueError("Unexpected end of expression")

        token = self.peek()

        if token[1] == '(':
            self.consume()
            expr = self.parse_expression()
            self.expect('operator')
            if self.peek()[1] != ')':
                raise ValueError("Unmatched parentheses")
            self.consume()
            return expr

        if token[0] == 'number':
            self.consume()
            return ASTNode('number', value=token[1])

        raise ValueError(f"Unexpected token: {token}")


def evaluate(node: ASTNode) -> float:
    if node.type == 'number':
        return node.value
    elif node.type == 'binop':
        left_val = evaluate(node.left)
        right_val = evaluate(node.right)

        if node.op == '+':
            return left_val + right_val
        elif node.op == '-':
            return left_val - right_val
        elif node.op == '*':
            return left_val * right_val
        elif node.op == '/':
            if right_val == 0:
                raise ZeroDivisionError("Division by zero")
            return left_val / right_val
    elif node.type == 'unary':
        operand_val = evaluate(node.operand)
        if node.op == '-':
            return -operand_val

    raise ValueError(f"Unknown node type: {node.type}")
